import React from "react";

const Navbar = () => {

  // 🔹 Time-based greeting
  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return "Good morning";
    if (hour < 18) return "Good afternoon";
    return "Good evening";
  };

  // 🔹 Static user (change null to simulate logout)
  const user = {
    name: "Priyanshu",
    isLoggedIn: true
  };

  return (
    <div className=" bg-gradient-to-br from-[#141E30] to-[#243B55] flex items-start justify-center p-6">

      <div className="w-full">

        {/* 🔹 Header */}
        <div className="flex items-center justify-between bg-white/10 backdrop-blur-xl border border-white/20 rounded-2xl px-6 py-4 shadow-lg">

          {/* 🔹 Left Section */}
          <div>
            <h1 className="text-2xl md:text-2xl font-semibold text-white">
              👋 {getGreeting()}, {user.isLoggedIn ? user.name : "Guest"}
            </h1>

            <p className="text-sm text-white/70 mt-1 tracking-wide">
              Be efficient, be productive.
            </p>
          </div>

          {/* 🔹 Right Section */}
          <div className="flex items-center gap-4">

            {/* Profile */}
            {user.isLoggedIn && (
              <div className="flex items-center gap-3 bg-white/10 px-3 py-2 rounded-xl border border-white/20 hover:bg-white/20 transition">
                <img
                  src="https://i.pravatar.cc/40"
                  alt="profile"
                  className="w-9 h-9 rounded-full border border-white/30"
                />
                <span className="text-white text-sm font-medium">
                  {user.name}
                </span>
              </div>
            )}

            {/* Login / Logout */}
            {user.isLoggedIn ? (
              <button className="px-5 py-2 rounded-xl bg-gradient-to-r from-red-500 to-pink-500 text-white font-medium hover:scale-105 transition">
                Logout
              </button>
            ) : (
              <button className="px-5 py-2 rounded-xl bg-gradient-to-r from-green-400 to-blue-500 text-white font-medium hover:scale-105 transition">
                Login
              </button>
            )}

          </div>

        </div>

      </div>
    </div>
  );
};

export default Navbar;
